    { sku: 'VH-2024-CIVIC', price: 26200, name: 'Honda Civic 2024' },
    { sku: 'VH-2024-ACCORD', price: 31800, name: 'Honda Accord 2024' },
    { sku: 'VH-2024-RAV4', price: 33400, name: 'Toyota RAV4 2024' },
    { sku: 'VH-2024-CRV', price: 32100, name: 'Honda CR-V 2024' },
    { sku: 'VH-2024-COROLLA', price: 22900, name: 'Toyota Corolla 2024' }
  ],
  source: 'mock-data',
  timestamp: new Date().toISOString()
};

return [{ json: mockCompetitorData }];

const competitorData = $items("Mock Competitor Data (Replace with Real API)")[0].json;
const localInventory = $input.all();

const updates = [];

for (const item of localInventory) {
  const product = item.json;
  const competitorProduct = competitorData.products.find(p => p.sku === product.sku);

  if (competitorProduct && competitorProduct.price < product.price) {
    updates.push({
      json: {
        id: product.id,
        sku: product.sku,
        oldPrice: product.price,
        price: competitorProduct.price - 0.01
      }
    });
  }
}

if (updates.length === 0) {
  return [{ json: { message: 'No price updates needed', timestamp: new Date().toISOString() } }];
}

return updates;
